@Composable
fun UserHeader(userId: String) {
    val formatter = remember(userId) { UserHeaderFormatter(userId) }
    Text(formatter.title())
}

@Composable
fun SearchBox() {
    var query by rememberSaveable { mutableStateOf("") }
    OutlinedTextField(value = query, onValueChange = { query = it })
}

@Composable
fun ProfileEditor(userId: String, initialName: String) {
    var name by rememberSaveable(userId) { mutableStateOf(initialName) }
    OutlinedTextField(value = name, onValueChange = { name = it })
}

data class FilterDraft(val keyword: String, val remoteOnly: Boolean)

val FilterDraftSaver = listSaver<FilterDraft, Any>(
    save = { listOf(it.keyword, it.remoteOnly) },
    restore = { FilterDraft(it[0] as String, it[1] as Boolean) }
)

@Composable
fun rememberFilterDraft() = rememberSaveable(
    stateSaver = FilterDraftSaver
) { mutableStateOf(FilterDraft("", false)) }

LazyColumn {
    items(messages, key = { it.clientId }) { message ->
        var expanded by rememberSaveable(message.clientId) {
            mutableStateOf(false)
        }
        MessageRow(message, expanded) { expanded = !expanded }
    }
}
